settings.custom_liquid:
{% if product.handle == 'roolo-reistas' %}
  <style>
    .roolo-benefits-grid {
      margin: 12px 0 18px 0;
      padding: 0;
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 9px 14px;
      text-align: left;
      max-width: 440px;
    }

    .roolo-benefit-item {
      display: flex;
      align-items: center;
      gap: 7px;
      font-size: 14.5px;
      line-height: 1.3;
      font-weight: 500;
      color: #1f1f1f;
      letter-spacing: 0.1px;
    }

    .roolo-benefit-check {
      width: 18px;
      height: 18px;
      min-width: 18px;
      border-radius: 50%;
      background: #111;
      color: #fff;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 11px;
      font-weight: 700;
      line-height: 1;
    }

    @media (max-width: 480px) {
      .roolo-benefits-grid {
        grid-template-columns: 1fr 1fr;
        gap: 8px 10px;
        margin: 10px 0 16px 0;
      }

      .roolo-benefit-item {
        font-size: 13.5px;
        gap: 6px;
      }

      .roolo-benefit-check {
        width: 16px;
        height: 16px;
        min-width: 16px;
        font-size: 10px;
      }
    }
  </style>

  <div class="roolo-benefits-grid">
    <div class="roolo-benefit-item">
      <span class="roolo-benefit-check">✓</span>
      <span>38+ kledingstukken</span>
    </div>

    <div class="roolo-benefit-item">
      <span class="roolo-benefit-check">✓</span>
      <span>Apart schoenenvak</span>
    </div>

    <div class="roolo-benefit-item">
      <span class="roolo-benefit-check">✓</span>
      <span>Kreukarm inpakken</span>
    </div>

    <div class="roolo-benefit-item">
      <span class="roolo-benefit-check">✓</span>
      <span>Bespaar op ruimbagage</span>
    </div>
  </div>
{% endif %}

{% assign today = 'now' | date: "%s" %}
{% assign morgen = today | plus: 86400 %}
{% assign dag = morgen | date: "%-d" %}
{% assign maand_nummer = morgen | date: "%-m" %}

{% case maand_nummer %}
  {% when '1' %}{% assign maand = 'januari' %}
  {% when '2' %}{% assign maand = 'februari' %}
  {% when '3' %}{% assign maand = 'maart' %}
  {% when '4' %}{% assign maand = 'april' %}
  {% when '5' %}{% assign maand = 'mei' %}
  {% when '6' %}{% assign maand = 'juni' %}
  {% when '7' %}{% assign maand = 'juli' %}
  {% when '8' %}{% assign maand = 'augustus' %}
  {% when '9' %}{% assign maand = 'september' %}
  {% when '10' %}{% assign maand = 'oktober' %}
  {% when '11' %}{% assign maand = 'november' %}
  {% when '12' %}{% assign maand = 'december' %}
{% endcase %}

<div style="text-align: left; margin-bottom: 24px;">
  <span style="color: #007000; font-size: 15px;">
    • Vandaag besteld, verzonden vóór: {{ dag }} {{ maand }}
  </span>
</div>
